Save Ticket\n            </button>\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n\nfunction TicketDetail({\n  projectPath,\n  ticketId,\n  board,\n  events,\n  onClose,\n  onChanged,\n  setToast\n}: {\n  projectPath: string;\n  ticketId: string;\n  board: BoardSnapshot;\n  events: RendererRunEvent[];\n  onClose: () => void;\n  onChanged: () => void;\n  setToast: (toast: Toast) => void;\n}): ReactElement {\n  const [ticket, setTicket] = useState<TicketRecord | null>(null);\n  const [title, setTitle] = useState(\"\");\n  const [priority, setPriority] = useState<TicketPriority>(\"medium\");\n  const [status, setStatus] = useState(\"todo\");\n  const [labels, setLabels] = useState(\"\");\n  const [markdown, setMarkdown] = useState(\"\");\n  const [busy, setBusy] = useState(false);\n  const [runId, setRunId] = useState<string | null>(null);\n\n  const load = useCallback(async () => {\n    const record = await window.relay.ticket.read(projectPath, ticketId);\n    setTicket(record);\n    setTitle(record.frontMatter.title);\n    setPriority(record.frontMatter.priority);\n    setStatus(record.frontMatter.status);\n    setLabels(record.frontMatter.labels.join(\", \"));\n    setMarkdown(record.markdown);\n    setRunId(record.frontMatter.lastRunId);\n  }, [projectPath, ticketId]);\n\n  useEffect(() => {\n    void load();\n  }, [load]);\n\n  const save = async (): Promise<void> => {\n    if (!ticket) return;\n    setBusy(true);\n    try {\n      await window.relay.ticket.save({\n        projectPath,\n        ticket: {\n          ...ticket,\n          markdown,\n          frontMatter: {\n            ...ticket.frontMatter,\n            title,\n            priority,\n            status,\n            labels: labels\n              .split(\",\")\n              .map((label) => label.trim())\n              .filter(Boolean)\n          }\n        }\n      });\n      setToast({ kind: \"success\", message: \"Ticket saved.\" });\n      onChanged();\n      await lo