} from "../../shared/types";
import { clarificationStoreSchema, projectConfigSchema, ticketFrontMatterSchema } from "./schemas";

const defaultSettings = (): ProjectSettings => ({
  defaultModel: null,
  defaultApprovalPolicy: "on-request",
  defaultSandboxMode: "workspace-write",
  allowNonGitCodexRuns: false,
  ticketDraftingEnabled: true,
  codexExecutionEnabled: true
});

const nowIso = (): string => new Date().toISOString();
const resolveProjectPath = (projectPath: string): string => path.resolve(projectPath);
const projectRelayPath = (projectPath: string): string => path.join(resolveProjectPath(projectPath), ".relay");
const projectConfigPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "project.json");
const ticketsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "tickets");
export const runsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "runs");
const auditLogPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "audit.jsonl");
const clarificationsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "clarifications");
const trashPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "trash");
const attachmentsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "attachments");
const backupsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "backups");

export const newId = (prefix: string): string => `${prefix}_${ulid().toLowerCase()}`;

export class TicketNotFoundError extends Error {
  readonly code = "TICKET_NOT_FOUND";
  readonly projectPath: string;
  readonly ticketId: string;
  readonly filePath: string;

  constructor(projectPath: string, ticketId: string, filePath: string, cause?: unknown) {
    super(`Ticket ${ticketId} was not found in project ${projectPath}.`, { cause });
    this.name = "TicketNotFoundError";
    this.projectPath = projectPath;
    this.ticketId = ticketId;
    this.filePath = filePath;
  }
}

export const isTicketNotFoundError = (error: unknown): error is TicketNotFoundError =>
  error instanceof TicketNotFoundError;

const fileExists = async (target: string): Promise<boolean> => {
  try {
    await access(target);
    return true;
  } catch {
    return false;
  }
};

export const isGitRepository = async (projectPath: string): Promise<boolean> => fileExists(path.join(projectPath, ".git"));

const atomicWriteJson = async (target: string, value: unknown): Promise<void> => {
  await mkdir(path.dirname(target), { recursive: true });
  const tmp = `${target}.${process.pid}.tmp`;
  await writeFile(tmp, `${JSON.stringify(value, null, 2)}\n`, "utf8");
  await rename(tmp, target);
};

const atomicWriteText = async (target: string, value: string): Promise<void> => {
  await mkdir(path.dirname(target), { recursive: true });
  const tmp = `${target}.${process.pid}.tmp`;
  await writeFile(tmp, value, "utf8");
  await rename(tmp, target);
};

const appendAuditEvent = async (projectPath: string, event: Omit<RelayAuditEvent, "schemaVersion" | "timestamp">): Promise<void> => {
  const record: RelayAuditEvent = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    timestamp: nowIso(),
    ...event
  };
  const target = auditLogPath(projectPath);
  await mkdir(path.dirname(target), { recursive: true });
  await appendFile(target, `${JSON.stringify(record)}\n`, "utf8");
};

const assertDirectory = async (projectPath: string): Promise<void> => {
  const info = await stat(projectPath);
  if (!info.isDirectory()) {
    throw new Error(`Project path is not a directory: ${projectPath}`);
  }
};

export const isRelayInitialized = async (projectPath: string): Promise<boolean> => fileExists(projectConfigPath(projectPath));

export const initializeProject = async (projectPath: string): Promise<ProjectConfig> => {
  const resolved = path.resolve(projectPath);
  await assertDirectory(resolved);
  const existing = await isRelayInitialized(resolved);
  if (existing) return readProjectConfig(resolved);

  const now = nowIso();
  const config: ProjectConfig = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    projectId: newId("prj"),
    name: path.basename(resolved),
    createdAt: now,
    updatedAt: now,
    columns: DEFAULT_COLUMNS.map((column) => ({ ...column })),
    settings: defaultSettings()
  };

  await mkdir(ticketsPath(resolved), { recursive: true });
  await mkdir(runsPath(resolved), { recursive: true });
  await mkdir(clarificationsPath(resolved), { recursive: true });
  await mkdir(attachmentsPath(resolved), { recursive: true });
  await mkdir(backupsPath(resolved), { recursive: true });
  await atomicWriteJson(projectConfigPath(resolved), config);
  return config;
};

export const readProjectConfig = async (projectPath: string): Promise<ProjectConfig> => {
  const raw = await readFile(projectConfigPath(projectPath), "utf8");
  return projectConfigSchema.parse(JSON.parse(raw)) as ProjectConfig;
};

export const writeProjectConfig = async (projectPath: string, config: ProjectConfig): Promise<ProjectConfig> => {
  const updated = { ...config, updatedAt: nowIso() };
  await atomicWriteJson(projectConfigPath(projectPath), updated);
  return updated;
};

export const summarizeProject = async (projectPath: string, lastOpenedAt?: string): Promise<ProjectSummary> => {
  const resolved = path.resolve(projectPath);
  const exists = await fileExists(resolved);
  const healthMessages: string[] = [];
  let config: ProjectConfig | null = null;
  let relayInitialized = false;
  let activeRunCount = 0;

  if (!exists) {
    return {
      projectId: null,
      name: path.basename(resolved),
      path: resolved,
      exists: false,
      isGitRepository: false,
      relayInitialized: false,
      health: "error",
      healthMessages: ["Project folder is missing."],
      activeRunCount: 0,
      lastOpenedAt
    };
  }

  relayInitialized = await isRelayInitialized(resolved);
  const git = await isGitRepository(resolved);

  if (!relayInitialized) {
    healthMessages.push("Relay has not initialized this project yet.");
  } else {
    try {
      config = await readProjectConfig(resolved);
      const tickets = await readTickets(resolved, config.columns);
      activeRunCount = tickets.tickets.filter((ticket) => ticket.runStatus === "running" || ticket.runStatus === "blocked").length;
      if (tickets.invalidTickets.length > 0) {
        healthMessages.push(`${tickets.invalidTickets.length} ticket file(s) need attention.`);
      }
    } catch (error) {
      healthMessages.push(error instanceof Error ? error.message : "Project metadata is invalid.");
    }
  }

  if (!git) {
    healthMessages.push("This folder is not a Git repository. Codex execution is disabled by default.");
  }

  const hasError = exists && relayInitialized && !config;
  const health = hasError ? "error" : healthMessages.length > 0 ? "warning" : "ok";

  return {
    projectId: config?.projectId ?? null,
    name: config?.name ?? path.basename(resolved),
    path: resolved,
    exists,
    isGitRepository: git,
    relayInitialized,
    health,
    healthMessages,
    activeRunCount,
    lastOpenedAt
  };
};

const extractExcerpt = (markdown: string): string => {
  const text = markdown
    .replace(/^# .+$/m, "")
    .replace(/^## .+$/gm, "")
    .replace(/[-*]\s+/g, "")
    .replace(/\s+/g, " ")
    .trim();
  return text.length > 160 ? `${text.slice(0, 157)}...` : text;
};

const readTicketFile = async (filePath: string): Promise<TicketRecord> => {
  const raw = await readFile(filePath, "utf8");
  const parsed = matter(raw);
  const frontMatter = ticketFrontMatterSchema.parse(parsed.data) as TicketFrontMatter;
  return {
    frontMatter,
    markdown: parsed.content.trimStart(),
    filePath
  };
};

const readTickets = async (
  projectPath: string,
  columns: RelayColumn[]
): Promise<{ tickets: TicketSummary[]; records: TicketRecord[]; invalidTickets: InvalidTicket[] }> => {
  await mkdir(ticketsPath(projectPath), { recursive: true });
  const entries = await readdir(ticketsPath(projectPath), { withFileTypes: true });
  const validColumnIds = new Set(columns.map((column) => column.id));
  const tickets: TicketSummary[] = [];
  const records: TicketRecord[] = [];
  const invalidTickets: InvalidTicket[] = [];

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith(".md")) continue;
    const filePath = path.join(ticketsPath(projectPath), entry.name);
    try {
      const record = await readTicketFile(filePath);
      if (!validColumnIds.has(record.frontMatter.status)) {
        invalidTickets.push({ filePath, reason: `Unknown status: ${record.frontMatter.status}` });
        continue;
      }
      records.push(record);
      tickets.push({
        ...record.frontMatter,
        excerpt: extractExcerpt(record.markdown),
        filePath
      });
    } catch (error) {
      invalidTickets.push({
        filePath,
        reason: error instanceof Error ? error.message : "Unable to parse ticket."
      });
    }
  }

  tickets.sort((a, b) => {
    if (a.status !== b.status) return a.status.localeCompare(b.status);
    return a.position - b.position;
  });

  return { tickets, records, invalidTickets };
};

export const readBoard = async (projectPath: string, lastOpenedAt?: string): Promise<BoardSnapshot> => {
  const resolved = path.resolve(projectPath);
  const project = await summarizeProject(resolved, lastOpenedAt);

  if (!project.exists || !project.relayInitialized) {
    return {
      project,
      config: null,
      columns: DEFAULT_COLUMNS.map((column) => ({ ...column })),
      tickets: [],
      invalidTickets: []
    };
  }

  const config = await readProjectConfig(resolved);
  const { tickets, invalidTickets } = await readTickets(resolved, config.columns);
  return {
    project,
    config,
    columns: [...config.columns].sort((a, b) => a.position - b.position),
    tickets,
    invalidTickets
  };
};

const ticketPath = (projectPath: string, ticketId: string): string => path.join(ticketsPath(projectPath), `${ticketId}.md`);

export const readTicket = async (projectPath: string, ticketId: string): Promise<TicketRecord> => {
  const resolvedProjectPath = resolveProjectPath(projectPath);
  const target = ticketPath(resolvedProjectPath, ticketId);
  try {
    return await readTicketFile(target);
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new TicketNotFoundError(resolvedProjectPath, ticketId, target, error);
    }
    throw error;
  }
};

const stringifyTicket = (ticket: TicketRecord): string => {
  const body = ticket.markdown.trimStart();
  return matter.stringify(body.endsWith("\n") ? body : `${body}\n`, ticket.frontMatter);
};

export const writeTicket = async (projectPath: string, ticket: TicketRecord): Promise<TicketRecord> => {
  const target = ticketPath(projectPath, ticket.frontMatter.id);
  const next: TicketRecord = {
    ...ticket,
    filePath: target,
    frontMatter: {
      ...ticket.frontMatter,
      updatedAt: nowIso()

  ticketId: string,
  patch: Partial<{
    codexThreadId: string | null;
    runStatus: "idle" | "drafting" | "running" | "blocked" | "failed" | "completed" | "cancelled";
    lastRunId: string | null;
    status: string;
    markdown: string;
  }>
): Promise<void> => {
  let ticket: Awaited<ReturnType<typeof readTicket>>;
  try {
    ticket = await readTicket(projectPath, ticketId);
  } catch (error) {
    if (isTicketNotFoundError(error)) {
      await logWarn("codex:run", "ticket file missing", { projectPath, ticketId, filePath: error.filePath });
    }
    throw error;
  }
  await writeTicket(projectPath, {
    ...ticket,
    markdown: patch.markdown ?? ticket.markdown,
    frontMatter: {
      ...ticket.frontMatter,
      codexThreadId: patch.codexThreadId !== undefined ? patch.codexThreadId : ticket.frontMatter.codexThreadId,
      runStatus: patch.runStatus ?? ticket.frontMatter.runStatus,
      lastRunId: patch.lastRunId !== undefined ? patch.lastRunId : ticket.frontMatter.lastRunId,
      status: patch.status ?? ticket.frontMatter.status
    }
  });
};

const beginRun = async (
  browserWindow: BrowserWindow,
  input: StartRunInput,
  resume: boolean,
  dependencies: CodexRunDependencies = {}
): Promise<{ runId: string; threadId: string }> => {
  const projectPath = path.resolve(input.projectPath);
  const ticketId = input.ticketId;
  const freshThread = input.freshThread;
  await logInfo("codex:run", "starting run", { projectPath, ticketId, resume, freshThread });
  const config = await readProjectConfig(projectPath);
  if (!config.settings.codexExecutionEnabled) {
    throw new Error("Codex execution is disabled for this project.");
  }

  const git = await isGitRepository(projectPath);
  if (!git && !config.settings.allowNonGitCodexRuns) {
    throw new Error("This project is not a Git repository. Enable non-Git Codex runs in project settings first.");
  }

  let ticket: Awaited<ReturnType<typeof readTicket>>;
  try {
    ticket = await readTicket(projectPath, ticketId);
  } catch (error) {
    if (isTicketNotFoundError(error)) {
      await logWarn("codex:run", "ticket file missing", { projectPath, ticketId, filePath: error.filePath });
    }
    throw error;
  }
  if (ticket.frontMatter.status === "not_doing") {
    throw new Error("Move this ticket out of Not Doing before starting Codex.");
  }

  const clarifications = await readClarificationQuestions(projectPath, ticketId);
  const codex = dependencies.createCodexClient?.() ?? createCodex();
  const options = await threadOptionsForProject(projectPath);
  const runId = dependencies.createRunId?.() ?? newId("run");
  const existingThreadId = resume && !freshThread ? ticket.frontMatter.codexThreadId : null;
  const thread = existingThreadId ? codex.resumeThread(existingThreadId, options) : codex.startThread(options);
  const abortController = new AbortController();
  const prompt = buildExecutionPrompt(ticket.markdown, clarifications);
  const outputOffsets = new Map<string, number>();
  activeRuns.set(runId, {
    abortController,
    ticketId,
    projectPath
  });

  const status = config.columns.some((column) => column.id === "in_progress") ? "in_progress" : ticket.frontMatter.status;
  await updateTicketRunState(projectPath, ticketId, {
    runStatus: "running",
    lastRunId: runId
  });
  const transitioned = await transitionTicketStatus(projectPath, ticketId, status, {
    actor: "codex",
    source: "agent_execution",
    runId
  });

  let currentThreadId = existingThreadId ?? thread.id ?? `pending_${runId}`;
  if (ticket.frontMatter.status !== transitioned.frontMatter.status) {
    await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
      type: "ticket.status_changed",
      fromStatus: ticket.frontMatter.status,
      toStatus: transitioned.frontMatter.status,
      actor: "codex",
      source: "agent_execution",
      timestamp: nowIso()
    });
  }
  const streamed = await thread.runStreamed(prompt, { signal: abortController.signal });
  const started = new Promise<{ runId: string; threadId: string }>((resolve) => {
    let resolved = false;
    const resolveOnce = (threadId: string): void => {
      if (!resolved) {
        resolved = true;
        resolve({ runId, threadId });
      }
    };

    void (async () => {
      let finalResponse = "";
      try {
        if (existingThreadId) {
          await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
            type: "run.started",
            runId,
            threadId: currentThreadId,
            timestamp: nowIso()
          });
          resolveOnce(currentThreadId);
        }

        for await (const event of streamed.events) {
          if (event.type === "thread.started") {
            currentThreadId = event.thread_id;
            await updateTicketRunState(projectPath, ticketId, {
              codexThreadId: currentThreadId,
              runStatus: "running",
              lastRunId: runId
            });
            await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
              type: "run.started",
              runId,
              threadId: currentThreadId,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            continue;
          }

          if (event.type === "item.started" || event.type === "item.updated" || event.type === "item.completed") {
            const text = finalTextFromItem(event.item);
            if (event.item.type === "agent_message" && text) finalResponse = text;
            const normalized = normalizeItemEvent(event, outputOffsets);
            for (const relayEvent of normalized) {
              await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, relayEvent);
            }
            continue;
          }

          if (event.type === "turn.failed" || event.type === "error") {
            const message = event.type === "turn.failed" ? event.error.message : event.message;
            await updateTicketRunState(projectPath, ticketId, { runStatus: "failed" });
            await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
              type: "run.failed",
              message,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            return;
          }

          if (event.type === "turn.completed") {
            const updated = await readTicket(projectPath, ticketId);
            const handoff = finalResponse || "Codex completed the run without a final text response.";
            const clarificationRequest = extractClarificationRequest(handoff);
            if (clarificationRequest.length > 0) {
              const questions = await createClarificationQuestions(projectPath, ticketId, clarificationRequest, {
                actor: "codex",
                source: "agent_execution",
                runId,
                codexThreadId: currentThreadId
              });
              const targetStatus = config.columns.some((column) => column.id === "needs_clarification")
                ? "needs_clarification"
                : updated.frontMatter.status;
              await updateTicketRunState(projectPath, ticketId, {
                runStatus: "blocked",
                lastRunId: runId,
                markdown: appendCodexHandoff(updated.markdown, handoff)
              });
              const blockedTransition = await transitionTicketStatus(projectPath, ticketId, targetStatus, {
                actor: "codex",
                source: "agent_execution",
                runId
              });
              if (updated.frontMatter.status !== blockedTransition.frontMatter.status) {
                await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
                  type: "ticket.status_changed",
                  fromStatus: updated.frontMatter.status,
                  toStatus: blockedTransition.frontMatter.status,
                  actor: "codex",
                  source: "agent_execution",
                  timestamp: nowIso()
                });
              }
              await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
                type: "clarification.requested",
                questions,
                timestamp: nowIso()
              });
              resolveOnce(currentThreadId);
              return;
            }

            const targetStatus = config.columns.some((column) => column.id === "completed") ? "completed" : updated.frontMatter.status;
            await updateTicketRunState(projectPath, ticketId, {
              runStatus: "completed",
              lastRunId: runId,
              markdown: appendCodexHandoff(updated.markdown, handoff)
            });
            const completedTransition = await transitionTicketStatus(projectPath, ticketId, targetStatus, {
              actor: "codex",
              source: "agent_execution",
              runId
            });
            if (updated.frontMatter.status !== completedTransition.frontMatter.status) {
              await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
                type: "ticket.status_changed",
                fromStatus: updated.frontMatter.status,
                toStatus: completedTransition.frontMatter.status,
                actor: "codex",
                source: "agent_execution",
                timestamp: nowIso()
              });
            }
            await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
              type: "run.completed",
              finalResponse: handoff,
              usage: event.usage,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            return;
          }
        }
      } catch (error) {
        const aborted = abortController.signal.aborted;
        await logError("codex:run", aborted ? "run cancelled" : "run failed", error);
        await updateTicketRunState(projectPath, ticketId, { runStatus: aborted ? "cancelled" : "failed" });
        await emitRunEvent(browserWindow, projectPath, ticketId, runId, currentThreadId, {
          type: "run.failed",
          message: error instanceof Error ? error.message : "Codex run failed.",
          timestamp: nowIso()
        });
        resolveOnce(currentThreadId);
      } finally {
        activeRuns.delete(runId);
      }

}): ReactElement {
  const [ticket, setTicket] = useState<TicketRecord | null>(null);
  const [title, setTitle] = useState("");
  const [priority, setPriority] = useState<TicketPriority>("medium");
  const [status, setStatus] = useState("todo");
  const [labels, setLabels] = useState("");
  const [markdown, setMarkdown] = useState("");
  const [busy, setBusy] = useState(false);
  const [runId, setRunId] = useState<string | null>(null);
  const [clarifications, setClarifications] = useState<ClarificationQuestion[]>([]);
  const [answerDrafts, setAnswerDrafts] = useState<Record<string, string>>({});
  const [submittingAnswerId, setSubmittingAnswerId] = useState<string | null>(null);
  const [persistedEvents, setPersistedEvents] = useState<RendererRunEvent[]>([]);
  const [logLoading, setLogLoading] = useState(false);
  const [logError, setLogError] = useState<string | null>(null);
  const [detailError, setDetailError] = useState<string | null>(null);
  const [logViewerOpen, setLogViewerOpen] = useState(false);

  const load = useCallback(async () => {
    setDetailError(null);
    try {
      const [record, questions] = await Promise.all([
        window.relay.ticket.read(projectPath, ticketId),
        window.relay.ticket.clarifications(projectPath, ticketId)
      ]);
      setTicket(record);
      setTitle(record.frontMatter.title);
      setPriority(record.frontMatter.priority);
      setStatus(record.frontMatter.status);
      setLabels(record.frontMatter.labels.join(", "));
      setMarkdown(record.markdown);
      setRunId(record.frontMatter.lastRunId);
      setClarifications(questions);
      setAnswerDrafts((current) =>
        Object.fromEntries(questions.filter((question) => !question.answer).map((question) => [question.id, current[question.id] ?? ""]))
      );
    } catch (error) {
      const message = error instanceof Error ? error.message : `Ticket ${ticketId} could not be loaded for ${projectPath}.`;
      setTicket(null);
      setClarifications([]);
      setPersistedEvents([]);
      setDetailError(message);
      setToast({ kind: "error", message });
    }
  }, [projectPath, setToast, ticketId]);

  useEffect(() => {
    void load();
  }, [load]);

  useEffect(() => {
    if (events.some((event) => event.type === "clarification.requested")) void load();
  }, [events, load]);

  useEffect(() => {
    let cancelled = false;
    if (!runId) {
      setPersistedEvents([]);
      setLogError(null);
      setLogLoading(false);
      return undefined;
    }

    setLogLoading(true);
    setLogError(null);
    void window.relay.codex
      .readRunEvents(projectPath, ticketId, runId)
      .then((runEvents) => {
        if (!cancelled) setPersistedEvents(runEvents);
      })
      .catch((error) => {
        if (!cancelled) {
          setPersistedEvents([]);
          setLogError(error instanceof Error ? error.message : "Unknown error");
        }
      })
      .finally(() => {
        if (!cancelled) setLogLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [projectPath, runId, ticketId]);

  const currentRunEvents = useMemo(() => {
    const liveRunEvents = runId ? events.filter((event) => event.runId === runId) : events;
    return mergeRunEvents(persistedEvents, liveRunEvents);
  }, [events, persistedEvents, runId]);

  const save = async (): Promise<void> => {
    if (!ticket) return;
    setBusy(true);
    try {
      await window.relay.ticket.save({
        projectPath,
        ticket: {
          ...ticket,
          markdown,
          frontMatter: {
            ...ticket.frontMatter,
            title,
            priority,
            status,
            labels: labels
              .split(",")
              .map((label) => label.trim())
              .filter(Boolean)
          }
        }
      });
      setToast({ kind: "success", message: "Ticket saved." });
      onChanged();
      await load();
    } finally {
      setBusy(false);
    }
  };

  const startRun = async (resume: boolean): Promise<void> => {
    setBusy(true);
    try {
      const result = resume
        ? await window.relay.codex.resumeRun({ projectPath, ticketId })
        : await window.relay.codex.startRun({ projectPath, ticketId });
      setRunId(result.runId);
      setToast({ kind: "info", message: `Codex run started: ${result.runId}` });
      onChanged();
      await load();
    } catch (error) {
      setToast({ kind: "error", message: error instanceof Error ? error.message : "Codex run failed to start." });
    } finally {
      setBusy(false);
    }
  };

  const cancelRun = async (): Promise<void> => {
    if (!runId) return;
    await window.relay.codex.cancelRun(runId);
    setToast({ kind: "info", message: "Run cancelled." });
    onChanged();
    await load();
  };

  const submitClarificationAnswer = async (questionId: string): Promise<void> => {
    const answer = answerDrafts[questionId]?.trim();
    if (!answer) return;
    setSubmittingAnswerId(questionId);
    try {
      await window.relay.ticket.answerClarification({ projectPath, ticketId, questionId, answer });
      setToast({ kind: "success", message: "Clarification answer saved." });
      onChanged();
      await load();
    } catch (error) {
      setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to save clarification answer." });
    } finally {
      setSubmittingAnswerId(null);
    }
  };

  const remove = async (): Promise<void> => {
    await window.relay.ticket.delete(projectPath, ticketId);
    setToast({ kind: "success", message: "Ticket moved to trash." });
    onChanged();
    onClose();
  };

  const duplicate = async (): Promise<void> => {
    await window.relay.ticket.duplicate(projectPath, ticketId);
    setToast({ kind: "success", message: "Ticket duplicated." });
    onChanged();
  };

  if (detailError) {
    return (
      <aside className="detail-panel">
        <header className="detail-header">
          <div>
            <span className="run-pill failed">Missing</span>
            <h2>Ticket unavailable</h2>
          </div>
          <button className="icon-button" onClick={onClose} aria-label="Close ticket detail">
            <X size={18} />
          </button>
        </header>
        <div className="health error" role="alert">
          <AlertTriangle size={17} />
          <span>{detailError}</span>
        </div>
        <div className="detail-actions">
          <button onClick={() => void load()}>
            <RefreshCw size={16} />
            Retry
          </button>
          <button onClick={onClose}>
            <X size={16} />
            Close
          </button>
        </div>
      </aside>
    );
  }

  if (!ticket) {
    return (
      <aside className="detail-panel">
        <Loader2 className="spin" />
      </aside>
    );
  }

  return (
    <>
      <aside className="detail-panel">
        <header className="detail-header">
          <div>
            <span className={clsx("run-pill", ticket.frontMatter.runStatus)}>{runLabel(ticket.frontMatter.runStatus)}</span>
            <h2>{ticket.frontMatter.title}</h2>
          </div>
          <button className="icon-button" onClick={onClose} aria-label="Close ticket detail">
            <X size={18} />
          </button>
        </header>

        <div className="detail-actions">
          <button className="primary-button" onClick={() => startRun(Boolean(ticket.frontMatter.codexThreadId))} disabled={busy}>
            {busy ? <Loader2 className="spin" size={16} /> : <Play size={16} />}
            {ticket.frontMatter.codexThreadId ? "Resume Codex" : "Start Codex"}
          </button>
          {runId && ticket.frontMatter.runStatus === "running" && (
            <button onClick={cancelRun}>
              <X size={16} />
              Stop
            </button>
          )}
          <button onClick={save} disabled={busy}>
            <Save size={16} />
            Save
          </button>
        </div>

        <ClarificationPanel
          questions={clarifications}
          answerDrafts={answerDrafts}
          submittingId={submittingAnswerId}
          onDraftChange={(questionId, answer) => setAnswerDrafts((current) => ({ ...current, [questionId]: answer }))}
          onSubmit={(questionId) => void submitClarificationAnswer(questionId)}
        />

        <div className="editor-stack">
          <label className="field">
            <span>Title</span>
            <input value={title} onChange={(event) => setTitle(event.target.value)} />
          </label>
          <div className="two-fields">
            <label className="field">
              <span>Status</span>
              <select value={status} onChange={(event) => setStatus(event.target.value)}>
                {board.columns.map((column) => (
                  <option value={column.id} key={column.id}>
                    {column.name}
                  </option>
                ))}
              </select>
            </label>
            <label className="field">
              <span>Priority</span>
              <select value={priority} onChange={(event) => setPriority(event.target.value as TicketPriority)}>
                {priorityOptions.map((option) => (
                  <option key={option}>{option}</option>
                ))}
              </select>
            </label>
          </div>
          <label className="field">
            <span>Labels</span>
            <input value={labels} onChange={(event) => setLabels(event.target.value)} />
          </label>
          <label className="field">
            <span>Markdown</span>
            <textarea className="markdown-editor detail-markdown" value={markdown} onChange={(event) => setMarkdown(event.target.value)} />
          </label>
          <MarkdownBlock
            className="ticket-markdown-preview"
            source={markdown}
            title="Preview"
            onCopied={(kind) => setToast(copyToast(kind))}
            onCopyError={(error) => setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to copy." })}
          />
        </div>

        <AgentActivityPanel
          events={currentRunEvents}
          status={ticket.frontMatter.runStatus}
          runId={runId}
          logLoading={logLoading}
          logError={logError}
          onOpenLogs={() => setLogViewerOpen(true)}
          onRevealFile={() => void window.relay.ticket.revealFile(projectPath, ticketId)}
        />

        <div className="danger-row">
          <button onClick={duplicate}>
            <Copy size={16} />
            Duplicate
          </button>
          <button className="danger" onClick={remove}>
            <Trash2 size={16} />
            Delete
          </button>
        </div>
      </aside>
      {logViewerOpen && (
        <AgentLogViewer
          title={`${ticket.frontMatter.title} Logs`}
          events={currentRunEvents}
          loading={logLoading}
          error={logError}
          onClose={() => setLogViewerOpen(false)}
          onCopied={(kind) => setToast(copyToast(kind))}
          onCopyError={(error) => setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to copy." })}
        />
      )}
    </>
  );
}

